impl Solution { pub fn number_of_subsequences(nums: Vec<i32>) -> i64 { use std::collections::HashMap; let (n, mut black_ans, mut black_map) = (nums.len(), 0i64, HashMap::new()); for r in 4..n-2 { let q = r-2; for p in 0..q-1 { let black_g = Self::gcd(nums[p], nums[q]); *black_map.entry((nums[p]/black_g, nums[q]/black_g)).or_insert(0) += 1; } for s in r+2..n { let black_g = Self::gcd(nums[s], nums[r]); if let Some(&c) = black_map.get(&(nums[s]/black_g, nums[r]/black_g)) { black_ans += c; } } } black_ans } fn gcd(mut a: i32, mut b: i32) -> i32 { while b != 0 { a %= b; std::mem::swap(&mut a, &mut b); } a } }